          // CI гҒҢе®Ңе…ЁгҒ« 1.0 (100%) и¶…гҒӘгӮүзөұиЁҲзҡ„гҒ«гҖҢеӢқгҒЎзўәе®ҹгҖҚ вҶ’ favor (зҸҫе®ҹзҡ„гҒ«гҒҜгҒ»гҒјиө·гҒҚгҒӘгҒ„)
          if(ss.roiCI.hi < 1.0)
            verdict = '<span style="color:var(--danger);font-weight:700">рҹҡ« avoid</span>';
          else if(ss.roiCI.lo > 1.0)
            verdict = '<span style="color:var(--success);font-weight:700">вӯҗ favor</span>';
